import{_ as e,o as t,c as r,a3 as o}from"./chunks/framework.CjquFG0V.js";const y=JSON.parse('{"title":"130. Saturday And Sunday Work","description":"","frontmatter":{"title":"130. Saturday And Sunday Work","eba":"Mental Health Services 2024-2028","topics":["hours","overtime"]},"headers":[],"relativePath":"ebas/mental-health/health-professionals/hours-of-work/130-saturday-and-sunday-work.md","filePath":"ebas/mental-health/health-professionals/hours-of-work/130-saturday-and-sunday-work.md"}'),n={name:"ebas/mental-health/health-professionals/hours-of-work/130-saturday-and-sunday-work.md"};function s(d,a,l,h,i,u){return t(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="_130-saturday-and-sunday-work" tabindex="-1">130. Saturday And Sunday Work <a class="header-anchor" href="#_130-saturday-and-sunday-work" aria-label="Permalink to &quot;130. Saturday And Sunday Work&quot;">​</a></h1><p><strong>130.1</strong> All rostered time of ordinary duty performed on Saturday and Sunday shall be paid for at the rate of time and a half.</p><p><strong>130.2</strong> Where Saturday and Sunday duties are required to be carried out in excess of the week’s work such duties are to be paid at the rate of double time.</p><p><strong>130.3</strong> Any recall to duty on a Saturday or Sunday shall be paid in accordance with <a href="/eba/ebas/mental-health/health-professionals/hours-of-work/128-overtime.html">clause 128</a>] (Overtime) as applicable.</p><p><strong>130.4</strong> By agreement with the Employer an Employee shall be allowed to take time off in lieu of overtime at the ordinary time rate as per <a href="/eba/ebas/mental-health/health-professionals/hours-of-work/128-overtime.html">clause 128.1</a>(d) of this Agreement.</p><p>Plain language terms: weekend penalty, weekend loading, weekend rates.</p>',6)])])}const m=e(n,[["render",s]]);export{y as __pageData,m as default};
